def get_str(keys):
    """Look up string resources. Returns tuple for list input, string for single."""
    if isinstance(keys, (list, tuple)):
        result = []
        for k in keys:
            for attr in ['title', 'button', 'toastmsg', 'tipsmsg', 'procbarmsg', 'itemmsg']:
                d = getattr(_en, attr, {})
                if k in d:
                    result.append(d[k])
                    break
            else:
                result.append(k)
        return tuple(result)
    for attr in ['title', 'button', 'toastmsg', 'tipsmsg', 'procbarmsg', 'itemmsg']:
        d = getattr(_en, attr, {})
        if keys in d:
            return d[keys]
    return keys

